            aOrbiterE = RotL64((aOrbiterE * 2036205056490578491U), 13U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterD) + 12571477440964330246U;
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 8436347026653095199U;
            aOrbiterH = RotL64((aOrbiterH * 17930734781213681573U), 21U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterG) + 14214789872073941940U;
