            aOrbiterJ = RotL64((aOrbiterJ * 13161681603528031511U), 41U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterB) + 15443240166233851298U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterC = ((aOrbiterC ^ aOrbiterJ) ^ 7311369180113240915U) ^ aOrbiterUpdateSaltE[((aIndex + 21U)) & S_SALT1];
