            aPrevious = aIngress;
            //
            aIngress = RotL64(aScrapLaneA[((aIndex + 9361U)) & S_BLOCK1], 30U) ^ RotL64(aSource[((aIndex + 8575U)) & S_BLOCK1], 21U);
            aIngress = TwistMix64::DiffuseA(((aIngress ^ aDomainWordIngress) ^ aNonceWordJ));
            //
            aCross = RotL64(aScrapLaneA[((S_BLOCK1 - aIndex + 8671U)) & S_BLOCK1], 37U) ^ RotL64(pSnow[((S_BLOCK1 - aIndex + 10853U)) & S_BLOCK1], 22U);
            aCross = TwistMix64::DiffuseA(((aCross ^ aDomainWordCross) ^ aNonceWordK));
            //
            aScatter = (RotL64(aCarry, 11U) ^ RotL64(aIngress, 37U)) + (RotL64(aPrevious, 52U) + RotL64(aCross, 23U));
