            aOrbiterC = (((aWandererA + RotL64(aPrevious, 10U)) + 1157119665207900473U) + aOrbiterAssignSaltC[((aIndex + 27U)) & S_SALT1]) + aNonceWordH;
            aOrbiterH = (((aWandererH + RotL64(aCross, 23U)) + RotL64(aCarry, 3U)) + 6823546624372055260U) + aNonceWordF;
            aOrbiterD = ((aWandererD + RotL64(aScatter, 47U)) + 14465564210523945121U) + aOrbiterAssignSaltF[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterA = ((aWandererF + RotL64(aIngress, 37U)) + RotL64(aCarry, 39U)) + 10667464548080807531U;
