            //
            aOrbiterD = (aOrbiterD + aOrbiterC) + 17102025528234481273U;
            aOrbiterF = (aOrbiterF ^ aOrbiterD) ^ 1841579177327486899U;
            aOrbiterF = RotL64((aOrbiterF * 3841603385577825265U), 47U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterG) + 2189493507896508972U;
            aOrbiterH = (aOrbiterH ^ aOrbiterB) ^ 18209567010094914374U;
            aOrbiterH = RotL64((aOrbiterH * 3737080408976852351U), 53U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterH) + 6697069234216868330U) + aOrbiterUpdateSaltC[(((31U - aIndex) + 18U)) & S_SALT1];
            aOrbiterI = ((aOrbiterI ^ aOrbiterJ) ^ 927471474577415372U) ^ aOrbiterUpdateSaltE[((aIndex + 16U)) & S_SALT1];
