            aIngress = TwistMix64::DiffuseB(aIngress);
            //
            aCross = (RotL64(aWindLaneC[((S_BLOCK1 - aIndex + 256U)) & S_BLOCK1], 56U) ^ RotL64(aWindLaneD[((S_BLOCK1 - aIndex + 5360U)) & S_BLOCK1], 13U));
            aCross ^= RotL64(aScrapLaneA[((S_BLOCK1 - aIndex + 2488U)) & S_BLOCK1], 5U);
